import math

def is_prime(n):
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(math.sqrt(n)) + 1, 2):
        if n % i == 0:
            return False
    return True

def lucas_lehmer_test(p):
    if not is_prime(p):
        return False

    if p == 2:
        return True

    M_p = (1 << p) - 1 

    s = 4

    for _ in range(p - 2):
        s = (s * s - 2) % M_p

    return s == 0
